//! The perception pipeline as ONE reusable, target-agnostic core — the single source of truth for
//! the per-frame sequence `detect → track → scene.update → scene_to_tick → encode_tick`, shared by
//! the native bin (`third-eye run`) and the wasm `PerceptionEngine`. No decode, no clock, no fs:
//! the caller hands it a [`crate::frame::Frame`] (native: from `frffmpeg`; wasm: written in-place
//! into the engine's frame buffer) and an explicit `pts_s`, and gets the packed `ConsciousTick`
//! wire bytes back.
//!
//! ## gnosis-frf + gnosis-antiqueue in the hot path (the cadence governor, per-frame)
//!
//! `cadence.rs` is the native, decoder-driven "as-fast-as-stable" governor. Its per-frame primitive
//! (a cheap luma signature + frame-to-frame motion energy), its value-door cost gate
//! (`certified_light`: GREEN = frf-parallel, RED = serial), and its antiqueue corridor
//! (`Broker`/`Producer::publish_certified`, no in-memory queue — back-pressure is frame-skip) are
//! lifted HERE so the SAME helpers run in the wasm hot path. On wasm, gnosis-frf takes its
//! single-threaded serial path (the `pool` module is `cfg(not(wasm32))`-gated and the `par_iter`
//! collectors fall to the serial cutoff), so the value-door verdict is honest telemetry and the
//! antiqueue corridor governs streaming cadence/stability. These are NOT stripped on wasm.
//!
//! The full perception work (`vision::detect`, tracking, scene admission, publish) is inherently
//! sequential within a single frame, so it is not parallelised across one frame; the frf-parallel
//! door governs the cheap cross-frame stat work exactly as `cadence` does, and the value-door's
//! certified cost still applies (GREEN collapses to the serial path on a single-threaded target).

use crate::frame::Frame;
use crate::physics::PhysicsConfig;
use crate::priors::PriorSet;
use crate::publish::{encode_tick, scene_to_relay_json, scene_to_tick, ConsciousTick, WorldMapping};
use crate::scene::SceneModel;
use crate::track::{Tracker, TrackerConfig};
use crate::vision::{detect, BackgroundModel, VisionConfig};

use std::sync::Arc;

use gnosis_antiqueue::{Broker, Chirality, Light, Producer, Stoplight, StoplightExt, certified_light};
use gnosis_frf::prelude::*;

/// Optional per-frame motion-deblur pre-pass config. When present on [`PerceptionOpts`], each frame's
/// RGB is deblurred (Richardson–Lucy line-PSF deconvolution, `distributed_inference::motion_deblur`)
/// BEFORE detection. Default is `None` (OFF — existing behaviour unchanged). The deblur itself is a
/// native-only seam (`cfg(not(wasm32))`); on wasm this config is carried but never acted on.
#[derive(Debug, Clone)]
pub struct MotionDeblurOpts {
    /// Blindly estimate the (angle, length) PSF per frame via `estimate_motion_psf`. When `true`,
    /// `angle_deg`/`length_px` are ignored. When `false`, the supplied angle/length are used.
    pub auto: bool,
    /// Blur direction in degrees (used when `auto == false`). Defaults to `0.0`.
    pub angle_deg: f32,
    /// Blur streak length in pixels (used when `auto == false`). `<= 1` is a no-op.
    pub length_px: f32,
    /// Richardson–Lucy iterations (clamped to `[0, 200]` inside the kernel).
    pub iterations: u32,
}

impl Default for MotionDeblurOpts {
    fn default() -> Self {
        // Sensible "guess + deconvolve" default: auto-estimate the PSF each frame, moderate iterations.
        MotionDeblurOpts { auto: true, angle_deg: 0.0, length_px: 9.0, iterations: 24 }
    }
}

/// Construction options for a [`PerceptionCore`]. The host supplies everything the native CLI flags
/// supplied (`--static-cam`, `--c-max`, `--object-priors`, hand-reach / max-impulse, plateau window)
/// plus the certified per-frame work cost the value-door reads (no probe needed — the cost is known).
#[derive(Debug, Clone)]
pub struct PerceptionOpts {
    /// Fixed camera (desk webcam): disable global-motion compensation so a moving object is not
    /// mistaken for a camera pan. Mirrors the bin's `--static-cam`.
    pub static_cam: bool,
    /// Causal-cone ceiling override (`--c-max`); `None` keeps the physics default.
    pub c_max: Option<f32>,
    /// Object priors JSON (the recon→third-eye material/mass/inertia feedback). The host read the
    /// file and passes the JSON STRING (lifts `priors.rs`'s `std::fs` read off the lib). Empty/absent
    /// → relative equal-density.
    pub object_priors_json: Option<String>,
    /// Affordance hand-reach / max-impulse overrides (`--hand-reach` / `--max-impulse`).
    pub hand_reach: Option<f32>,
    pub max_impulse: Option<f32>,
    /// C0-C3 metacog plateau window (`--plateau-window`).
    pub plateau_window: Option<u32>,
    /// How the normalised frame maps into the worldsim ground plane.
    pub world_w: f32,
    pub world_d: f32,
    /// The CERTIFIED per-frame stat-work cost (ns) the value-door gates on, and the per-item
    /// dispatch cost (ns). The cost is read from the admission cert, not probed (the value-door
    /// doctrine: YELLOW is vacuous). Defaults mirror `CadenceConfig` (`dispatch_ns = 100`).
    pub work_ns: u64,
    pub dispatch_ns: u64,
    /// Source id / layer id stamped into the relay frame.
    pub source_id: String,
    pub layer_id: String,
    /// OPTIONAL per-frame motion-deblur pre-pass (default `None` = OFF). When set, each frame's RGB is
    /// deblurred before detection. Native-only seam; carried-but-ignored on wasm.
    pub motion_deblur: Option<MotionDeblurOpts>,
}

impl Default for PerceptionOpts {
    fn default() -> Self {
        PerceptionOpts {
            static_cam: false,
            c_max: None,
            object_priors_json: None,
            hand_reach: None,
            max_impulse: None,
            plateau_window: None,
            world_w: 10.0,
            world_d: 10.0,
            // A conservative certified per-frame stat cost: the cheap luma-sig + motion work is
            // sub-microsecond on a downscaled frame, below the 100ns dispatch cost, so the
            // value-door rests RED (serial) by default — exactly the small-bursty regime the
            // GNOSIS_FRF_SERIAL_CUTOFF doctrine prescribes. The host may raise this if it certifies
            // heavier per-frame work.
            work_ns: 64,
            dispatch_ns: 100,
            source_id: "third-eye".to_string(),
            layer_id: "perception".to_string(),
            motion_deblur: None, // OFF by default — existing behaviour unchanged
        }
    }
}

/// The cadence governor's per-frame stat primitive: a 16x16 luma signature (a cheap content
/// fingerprint). Identical math to `cadence::frame_stat`'s signature; the luma weights come from the
/// single-source `simd::luma_u8` kernel so every module agrees byte-for-byte.
fn frame_sig(f: &Frame) -> [u8; 256] {
    let w = f.width as usize;
    let h = f.height as usize;
    let px = &f.rgb;
    let mut sig = [0u8; 256];
    for by in 0..16usize {
        let y0 = by * h / 16;
        let y1 = ((by + 1) * h / 16).max(y0 + 1).min(h);
        let ystep = ((y1 - y0) / 4).max(1);
        for bx in 0..16usize {
            let x0 = bx * w / 16;
            let x1 = ((bx + 1) * w / 16).max(x0 + 1).min(w);
            let xstep = ((x1 - x0) / 4).max(1);
            let mut s: u64 = 0;
            let mut c: u64 = 0;
            let mut y = y0;
            while y < y1 {
                let mut x = x0;
                while x < x1 {
                    let i = (y * w + x) * 3;
                    s += crate::simd::luma_u8(px[i], px[i + 1], px[i + 2]) as u64;
                    c += 1;
                    x += xstep;
                }
                y += ystep;
            }
            sig[by * 16 + bx] = if c > 0 { (s / c) as u8 } else { 0 };
        }
    }
    sig
}

/// Per-frame governor telemetry (the cadence/stability signal carried alongside the perception).
#[derive(Debug, Clone, Copy)]
pub struct GovernorTick {
    /// The value-door verdict for the per-frame stat work ("GREEN" frf-parallel / "RED" serial).
    pub light: &'static str,
    /// Frame-to-frame motion energy in [0,1] (scene activity).
    pub motion: f32,
    /// antiqueue corridor: frame-events published so far this session.
    pub published: usize,
    /// antiqueue corridor: frame-events delivered so far this session.
    pub delivered: usize,
    /// antiqueue corridor: peak in-flight (the back-pressure signal).
    pub peak_in_flight: usize,
}

fn light_name(l: Light) -> &'static str {
    match l {
        Light::Green => "GREEN",
        Light::Red => "RED",
        Light::Yellow => "YELLOW",
    }
}

/// The perception core: owns the cross-tick state (EMA `BackgroundModel`, `Tracker`, `SceneModel`)
/// and the gnosis-frf/antiqueue cadence governor. One [`Self::observe`] per frame mutates that state
/// in place and emits the packed `ConsciousTick` wire bytes. The PERCEPTION WINDOW is this struct,
/// not a single call.
pub struct PerceptionCore {
    bg: BackgroundModel,
    vcfg: VisionConfig,
    tracker: Tracker,
    scene: SceneModel,
    map: WorldMapping,
    seq: u32,
    source_id: String,
    layer_id: String,
    /// OPTIONAL motion-deblur pre-pass config (None = OFF). Acted on only on native targets.
    motion_deblur: Option<MotionDeblurOpts>,
    // ── gnosis-frf value-door + gnosis-antiqueue corridor (the cadence governor, per-frame) ──
    work_ns: u64,
    dispatch_ns: u64,
    broker: Arc<Broker>,
    producer: Producer,
    prev_sig: Option<[u8; 256]>,
    last_light: Light,
    last_motion: f32,
}

impl PerceptionCore {
    /// Build a perception core from explicit options. `width`/`height`/`fps` describe the frames the
    /// caller will hand to [`Self::observe`]; they are advisory here (each `Frame` carries its dims).
    pub fn new(_width: u32, _height: u32, _fps: f64, opts: &PerceptionOpts) -> Result<Self, String> {
        let mut vcfg = VisionConfig::default();
        if opts.static_cam {
            vcfg.compensate = false;
        }
        let mut pcfg = PhysicsConfig::default();
        if let Some(c) = opts.c_max {
            pcfg.c_max = c;
        }
        let mut scene = SceneModel::new(pcfg);
        if opts.hand_reach.is_some() || opts.max_impulse.is_some() {
            scene.set_affordance_config(opts.hand_reach, opts.max_impulse);
        }
        if let Some(w) = opts.plateau_window {
            scene.set_metacog_plateau_window(w);
        }
        if let Some(json) = &opts.object_priors_json {
            let trimmed = json.trim();
            if !trimmed.is_empty() {
                let set = PriorSet::from_json(trimmed)
                    .map_err(|e| format!("object_priors_json: {e}"))?;
                scene.set_priors(set);
            }
        }

        // antiqueue corridor for processed frame-events (mirrors cadence::run). A finite green
        // window expresses the admission rate; peak_in_flight is the back-pressure signal.
        let broker = Broker::local();
        broker.declare_consumer_certified(
            "scene",
            Stoplight::resting(64, 8, 0),
            Chirality::Compression,
            0, // unattested handler -> default green-window gate
            |_m| Ok(()),
        );
        let producer = broker.producer("");

        Ok(PerceptionCore {
            bg: BackgroundModel::new(),
            vcfg,
            tracker: Tracker::new(TrackerConfig::default()),
            scene,
            map: WorldMapping { world_w: opts.world_w, world_d: opts.world_d },
            seq: 0,
            source_id: opts.source_id.clone(),
            layer_id: opts.layer_id.clone(),
            motion_deblur: opts.motion_deblur.clone(),
            work_ns: opts.work_ns.max(1),
            dispatch_ns: opts.dispatch_ns,
            broker,
            producer,
            prev_sig: None,
            last_light: Light::Red,
            last_motion: 0.0,
        })
    }

    /// Run the gnosis-frf value-door + gnosis-antiqueue corridor over this frame's cheap stat work,
    /// exactly as `cadence::process_batch`/`flush` do per batch. The value-door reads the CERTIFIED
    /// cost (no probe); GREEN runs the frf-parallel collector (which, on a single-threaded target,
    /// is the serial path), RED runs serial. The processed frame-event is admitted into the corridor.
    fn run_governor(&mut self, frame: &Frame) {
        let light = certified_light(self.work_ns, self.dispatch_ns);
        // The frf-parallel door over the (single) cheap stat. On wasm/single-thread this collapses
        // to the serial cutoff; on native multi-thread a GREEN cert would fan it out. One frame's
        // stat is one item, so this is the door's verdict carried honestly, not a perf claim.
        let sig = match light {
            Light::Green => {
                let v: Vec<[u8; 256]> = core::slice::from_ref(frame)
                    .par_iter()
                    .map(frame_sig)
                    .with_sub_chunks_auto()
                    .collect();
                v.into_iter().next().unwrap_or([0u8; 256])
            }
            _ => frame_sig(frame),
        };
        // Frame-to-frame motion energy via the SIMD-accelerated L1 kernel (u8x16 on wasm+simd128).
        let motion = self.prev_sig.map(|p| crate::simd::sig_motion_256(&sig, &p)).unwrap_or(0.0);
        self.prev_sig = Some(sig);
        self.last_light = light;
        self.last_motion = motion;
        // Admit the processed frame-event into the antiqueue corridor (back-pressure = frame-skip;
        // no in-memory queue). The corridor governs streaming cadence/stability.
        let _ = self.producer.publish_certified("scene.frame", sig.to_vec());
    }

    /// The optional motion-deblur pre-pass (NATIVE). When `self.motion_deblur` is set, convert the
    /// frame's interleaved RGB24 `[0,255]` to linear RGB `[0,1]` f32, run the line-PSF Richardson–Lucy
    /// deconvolution (`distributed_inference::motion_deblur`), and return a fresh `Frame` carrying the
    /// deblurred RGB24. Returns `None` when the pre-pass is OFF or the deconvolution was a no-op/failed
    /// — the caller then detects on the original frame (existing behaviour, zero extra cost when OFF).
    #[cfg(not(target_arch = "wasm32"))]
    fn motion_deblur_prepass(&self, frame: &Frame) -> Option<Frame> {
        use distributed_inference::motion_deblur::{
            estimate_motion_psf, motion_deblur_rgb_f32, MotionDeblurConfig,
        };
        let md = self.motion_deblur.as_ref()?;
        let (w, h) = (frame.width, frame.height);
        let n = (w as usize) * (h as usize) * 3;
        if w == 0 || h == 0 || frame.rgb.len() != n {
            return None;
        }
        // u8 [0,255] interleaved RGB24 -> f32 [0,1] interleaved (same layout the kernel expects).
        let rgb_f32: Vec<f32> = frame.rgb.iter().map(|&b| b as f32 / 255.0).collect();
        // Auto-estimate the PSF per frame, or use the supplied angle/length.
        let (angle_deg, length_px) = if md.auto {
            estimate_motion_psf(&rgb_f32, w, h)
        } else {
            (md.angle_deg, md.length_px)
        };
        let cfg = MotionDeblurConfig {
            angle_deg,
            length_px,
            iterations: md.iterations,
            damping: 1.0,
            emit_layers: false, // lean per-frame path; diagnostic layers are a UX concern, not detection
        };
        let result = match motion_deblur_rgb_f32(&rgb_f32, w, h, &cfg) {
            Ok(r) => r,
            // A deblur failure must NOT break perception — fall back to the original frame.
            Err(_) => return None,
        };
        // f32 [0,1] -> u8 [0,255] interleaved RGB24, into a fresh frame (originals are immutable).
        let rgb_u8: Vec<u8> = result
            .rgb
            .iter()
            .map(|&v| (v.clamp(0.0, 1.0) * 255.0 + 0.5) as u8)
            .collect();
        Some(Frame { index: frame.index, pts_s: frame.pts_s, width: w, height: h, rgb: rgb_u8 })
    }

    /// The optional motion-deblur pre-pass (WASM no-op). The deblur kernel lives in the native-only
    /// `distributed-inference` crate, so on wasm the pre-pass is never linked and always returns `None`
    /// (detect runs on the original frame). The `motion_deblur` config is carried but inert here.
    #[cfg(target_arch = "wasm32")]
    fn motion_deblur_prepass(&self, _frame: &Frame) -> Option<Frame> {
        None
    }

    /// Perceive one frame: run the gnosis-frf/antiqueue governor, then the full sequential
    /// perception (`detect → track → scene.update → scene_to_tick`), and return the `ConsciousTick`.
    /// `pts_s` is the host clock (no wall-clock read inside the lib).
    pub fn observe_tick(&mut self, frame: &Frame, pts_s: f64) -> ConsciousTick {
        self.run_governor(frame);
        // OPTIONAL motion-deblur pre-pass: when enabled, deblur the frame's RGB before detection.
        // Returns `Some(deblurred_frame)` only when the pre-pass ran and changed the buffer; `None`
        // (the default) means detect on the original frame — zero-cost when the feature is OFF.
        let deblurred = self.motion_deblur_prepass(frame);
        let detect_frame: &Frame = deblurred.as_ref().unwrap_or(frame);
        let (props, _fg) = detect(detect_frame, &mut self.bg, &self.vcfg);
        self.tracker.step(&props, pts_s);
        self.scene.update(&self.tracker);
        let tick = scene_to_tick(
            &self.scene,
            self.seq,
            &self.source_id,
            &self.layer_id,
            pts_s,
            &self.map,
        );
        self.seq += 1;
        tick
    }

    /// Perceive one frame and return the PACKED FlowCodec wire bytes (10-byte header + relay JSON
    /// payload) — the zero-copy hot-path output the host forwards straight onto the WS.
    pub fn observe_packed(&mut self, frame: &Frame, pts_s: f64) -> Vec<u8> {
        let tick = self.observe_tick(frame, pts_s);
        encode_tick(&tick)
    }

    /// Human-readable relay JSON for the LAST-perceived scene state (debug path, NOT the hot path).
    /// Does not advance the sequence; reflects the scene after the most recent `observe`.
    pub fn relay_json(&self, pts_s: f64) -> String {
        scene_to_relay_json(&self.scene, &self.source_id, &self.layer_id, pts_s, &self.map)
    }

    /// Number of fully-certified (Accept) entities in the current scene.
    pub fn accepted(&self) -> usize {
        self.scene.accepted()
    }

    /// The current per-frame governor telemetry (value-door verdict + motion + corridor counters).
    pub fn governor_tick(&self) -> GovernorTick {
        let tel = self.broker.telemetry();
        GovernorTick {
            light: light_name(self.last_light),
            motion: self.last_motion,
            published: tel.published,
            delivered: tel.delivered,
            peak_in_flight: tel.peak_in_flight,
        }
    }

    /// Read-only access to the scene model (affordances / counterfactuals / metacog / knowledge).
    pub fn scene(&self) -> &SceneModel {
        &self.scene
    }

    /// The next sequence number that will be stamped.
    pub fn sequence(&self) -> u32 {
        self.seq
    }
}
